      const tierEl = detailEl.querySelector('#queue-tier');
      const riskEl = detailEl.querySelector('#queue-change-risk');
      const pfEl = detailEl.querySelector('#queue-pfail');
      const vEl = detailEl.querySelector('#queue-verify');
