	          if (!window.confirm(`Request changes?\n${url}${suffix}`)) return;

	          requestChangesBtn.disabled = true;
	          if (approvePrBtn) approvePrBtn.disabled = true;
	          if (mergePrBtn) mergePrBtn.disabled = true;
